UPDATE dbo.taxpayers_main
SET outlet_address = LTRIM(RTRIM(
    REPLACE(REPLACE(REPLACE(outlet_address, '   ',' '),'  ',' '),'  ',' ')
));

-- Name normalization
UPDATE dbo.taxpayers_main
SET outlet_name = REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(
    outlet_name, '.',''),',',''),'#',''),'"',''),'''',''),'-',' ');

UPDATE dbo.taxpayers_main SET outlet_name = REPLACE(outlet_name, ' & ', ' AND ');
UPDATE dbo.taxpayers_main SET outlet_name = REPLACE(outlet_name, ' LLC',  '');
UPDATE dbo.taxpayers_main SET outlet_name = REPLACE(outlet_name, ' INC',  '');
UPDATE dbo.taxpayers_main SET outlet_name = REPLACE(outlet_name, ' CORP', '');
UPDATE dbo.taxpayers_main SET outlet_name = REPLACE(outlet_name, ' LTD',  '');
UPDATE dbo.taxpayers_main SET outlet_name = REPLACE(outlet_name, ' CO',   '');
UPDATE dbo.taxpayers_main SET outlet_name = REPLACE(outlet_name, ' DBA',  '');
UPDATE dbo.taxpayers_main SET outlet_name = REPLACE(outlet_name, ' LP',   '');

UPDATE dbo.taxpayers_main
SET outlet_name = LTRIM(STUFF(outlet_name, 1, 4, ''))
WHERE outlet_name LIKE 'THE %';

UPDATE dbo.taxpayers_main
SET outlet_name = LTRIM(RTRIM(
    REPLACE(REPLACE(REPLACE(outlet_name, '   ',' '),'  ',' '),'  ',' ')
));

-- Dedup: keep latest record per location
WITH CTE AS (
    SELECT *, ROW_NUMBER() OVER (
        PARTITION BY CONCAT(
            UPPER(ISNULL(outlet_name, taxpayer_number)), '-',
            UPPER(outlet_address), '-',
            UPPER(outlet_city)
        )
        ORDER BY TRY_CAST(outlet_permit_issue_date AS DATE) DESC
    ) AS row_num
    FROM dbo.taxpayers_main
)
DELETE FROM CTE WHERE row_num > 1;

