-- Dedup: keep latest active license per location
WITH CTE AS (
    SELECT *, ROW_NUMBER() OVER (
        PARTITION BY CONCAT(
            UPPER(ISNULL(trade_name, license_id)), '-',
            UPPER(address), '-',
            UPPER(city)
        )
        ORDER BY
            CASE WHEN primary_status = 'Active' THEN 0 ELSE 1 END,
            TRY_CAST(current_issued_date AS DATE) DESC
    ) AS row_num
